#include <bits/stdc++.h>
using namespace std;

// foot indices: 0=FL, 1=FR, 2=RL, 3=RR  (matching initial positions)
// direction: 0=north, 1=east, 2=south, 3=west
int dx[] = {0, 1, 0, -1}; // forward vectors for each direction
int dy[] = {1, 0, -1, 0}; // y increases north (up), x increases east (right)

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;
    // foot positions: (x,y). initially:
    // FL: x=-1,y=1   FR: x=1,y=1   RL: x=-1,y=-1   RR: x=1,y=-1
    // (facing north)
    int x[4], y[4];
    x[0] = -1; y[0] = 1;   // FL
    x[1] = 1;  y[1] = 1;   // FR
    x[2] = -1; y[2] = -1;  // RL
    x[3] = 1;  y[3] = -1;  // RR

    int dir = 0; // 0=north

    // map foot name to index
    auto footIdx = [](const string& s) -> int {
        if (s == "FL") return 0;
        if (s == "FR") return 1;
        if (s == "RL") return 2;
        return 3; // RR
    };

    // bounds tracking
    int minX = -1, maxX = 1, minY = -1, maxY = 1;

    auto updateBounds = [&]() {
        for (int i = 0; i < 4; i++) {
            minX = min(minX, x[i]);
            maxX = max(maxX, x[i]);
            minY = min(minY, y[i]);
            maxY = max(maxY, y[i]);
        }
    };

    auto checkCollision = [&]() -> bool {
        for (int i = 0; i < 4; i++)
            for (int j = i+1; j < 4; j++)
                if (x[i] == x[j] && y[i] == y[j]) return true;
        return false;
    };

    for (int i = 0; i < N; i++) {
        string inst;
        cin >> inst;
        int fi = footIdx(inst.substr(0, 2));
        char action = inst[2];
        if (action == 'P') {
            // pivot 90° clockwise around foot fi
            // pivot point
            int px = x[fi], py = y[fi];
            // new direction
            dir = (dir + 1) % 4;
            // rotate all other feet around (px, py) by 90° clockwise:
            // (x', y') = (px + (y - py), py - (x - px))
            // Because: clockwise rotation of vector (dx,dy) gives (dy, -dx)
            for (int j = 0; j < 4; j++) {
                if (j == fi) continue;
                int oldx = x[j], oldy = y[j];
                int relx = oldx - px;
                int rely = oldy - py;
                // clockwise: (relx, rely) -> (rely, -relx)
                x[j] = px + rely;
                y[j] = py - relx;
            }
        } else {
            // move the foot
            int moveDir;
            if (action == 'F') moveDir = dir;       // forward
            else if (action == 'B') moveDir = (dir + 2) % 4; // back
            else if (action == 'R') moveDir = (dir + 1) % 4; // right
            else if (action == 'L') moveDir = (dir + 3) % 4; // left
            else continue;

            x[fi] += dx[moveDir];
            y[fi] += dy[moveDir];
        }

        // check collision after this instruction
        if (checkCollision()) {
            cout << -1 << '\n';
            return 0;
        }
        updateBounds();
    }

    int width = maxX - minX + 1;
    int height = maxY - minY + 1;
    long long area = 1LL * width * height;
    cout << area << '\n';

    return 0;
}
